Here's my planned update() body (goes inside 'def update(self, iterable, **kwds):', same signature as before — I did NOT add/change a decorator):

    def update(self, iterable, **kwds):
        def _merge_value(old_value, new_value):
            if isinstance(old_value, dict) and isinstance(new_value, dict):
                for k, v in new_value.items():
                    old_value[k] = _merge_value(old_value[k], v) if k in old_value else v
                return old_value
            elif isinstance(old_value, Sequence) and isinstance(new_value, Sequence):
                old_value.feature = _merge_value(old_value.feature, new_value.feature)
                return old_value
            else:
                return new_value

        def _update_value(key, value):
            self[key] = _merge_value(self[key], value) if key in self else value

        if hasattr(iterable, 'keys'):
            for key in iterable.keys():
                _update_value(key, iterable[key])
        else:
            for key, value in iterable:
                _update_value(key, value)
        for key in kwds:
            _update_value(key, kwds[key])

Notes: it mutates old_value in place for dict/Sequence-of-dict cases, then always reassigns via self[key] = ... so __setitem__ (and your decorator) still fires and _column_requires_decoding stays correct. Feel free to wrap this whole method with your keep_features_dicts_synced decorator - I don't touch __setitem__/__delitem__/pop/etc, only update(). Go ahead and apply your decorator on top of this.
